<template>
  <v-app class="app">
    <div class="content">
      <v-text-field
        disabled
        v-model="hint"
        class="hint"
        :error-messages="errorMessages"
        outlined
      />
      <!-- <v-text-field disabled v-model="answer" outlined class="answer" /> -->
      <div class="grid-buttons">
        <v-btn class="btn" disabled>sin</v-btn>
        <v-btn class="btn" disabled>cos</v-btn>
        <v-btn class="btn" disabled>tg</v-btn>
        <v-btn class="btn" @click="doAction('^')" color="green"> ^ </v-btn>
        <div class="empty"></div>

        <v-btn class="btn" @click="numbers('7')"> 7 </v-btn>
        <v-btn class="btn" @click="numbers('8')"> 8 </v-btn>
        <v-btn class="btn" @click="numbers('9')"> 9 </v-btn>
        <v-btn class="btn" @click="doAction('/')" color="green"> / </v-btn>

        <v-btn class="btn" @click="clear">
          <v-icon dark> mdi-delete </v-icon>
        </v-btn>
        <v-btn class="btn" @click="numbers('4')"> 4 </v-btn>
        <v-btn class="btn" @click="numbers('5')"> 5 </v-btn>
        <v-btn class="btn" @click="numbers('6')"> 6 </v-btn>

        <v-btn class="btn" @click="doAction('*')" color="green"> * </v-btn>
        <div class="empty"></div>
        <v-btn class="btn" @click="numbers('1')"> 1 </v-btn>
        <v-btn class="btn" @click="numbers('2')"> 2 </v-btn>
        <v-btn class="btn" @click="numbers('3')"> 3 </v-btn>
        <v-btn class="btn" @click="doAction('-')" color="green"> - </v-btn>
        <div class="empty"></div>
        <v-btn class="btn" @click="numbers('0')"> 0 </v-btn>
        <v-btn class="btn" @click="comma">,</v-btn>
        <div class="empty"></div>
        <v-btn class="btn" @click="doAction('+')" color="green"> + </v-btn>

        <v-btn class="btn" @click="doEqual"> = </v-btn>
      </div>
    </div>
  </v-app>
</template>

<script>
export default {
  name: "App",

  components: {},
  methods: {
    comma() {
      this.answer += ",";
      this.hint += ",";
    },
    commaToDot(str) {
      for (let i in str) {
        if (str[i] === ",") {
          let res = str.substring(0, i) + "." + str.substring(++i, str.length);
          return res;
        }
      }
      return str;
    },
    dotToComma(str) {
      for (let i in str) {
        if (str[i] === ".") {
          let res = str.substring(0, i) + "," + str.substring(++i, str.length);

          return res;
        }
      }
      return str;
    },
    numbers(n) {
      if (this.afterEqual) {
        this.hint = "";
        this.afterEqual = false;
      }
      if (!this.isNew) {
        this.answer += n;
      } else {
        this.errorMessages = [];
        this.answer = n;
        this.isNew = false;
      }
      this.hint += n;
    },
    doEqual() {
      //ифаем отсутствие второго аргумента
      if (!this.isLastAction()) {
        if (this.action === "+") {
          let sum = Number(this.num1) + Number(this.commaToDot(this.answer));
          let ans = this.dotToComma(this.removeDot(String(sum.toFixed(8).replace(/0*$/,""))));
          this.answer = ans;
          this.hint += " = " + ans;
        } else if (this.action === "-") {
          let dif = Number(this.num1) - Number(this.commaToDot(this.answer));
          let ans = this.dotToComma(this.removeDot(String(dif.toFixed(8).replace(/0*$/,""))));
          this.answer = ans;
          this.hint += " = " + ans;
        } else if (this.action === "*") {
          let ans = this.dotToComma(
            String(Number(this.num1) * Number(this.commaToDot(this.answer)))
          );
          this.answer = ans;
          this.hint += " = " + ans;
        } else if (this.action === "/") {
          if (this.answer === "0") {
            this.errorMessages.push("Math Error");
            this.answer = "Math Error";
          } else {
            let ans = this.dotToComma(
              String(Number(this.num1) / Number(this.commaToDot(this.answer)))
            );
            this.answer = ans;
            this.hint += " = " + ans;
          }
        } else if (this.action === "^") {
          let ans = this.dotToComma(
            String(
              Math.pow(Number(this.num1), Number(this.commaToDot(this.answer)))
            )
          );

          this.answer = ans;
          this.hint += " = " + ans;
        }

        this.num1 = "";
        if (this.errorMessages[0] !== "Math Error") {
          this.errorMessages = [];
        }
        this.action = "";
        this.isNew = true;
        this.afterEqual = true;
        this.isThereAction = false;
      } else {
        this, this.errorMessages.push("You must provide the second argument");
      }
    },
    backspace() {
      if (this.answer.length > 0) {
        this.answer = this.answer.substring(0, this.answer.length - 1);
        this.hint = this.hint.substring(0, this.hint.length - 1);
      }
      this.errorMessages = [];
    },
    isLastAction() {
      if (
        this.hint.charAt(this.hint.length - 2) == "+" ||
        this.hint.charAt(this.hint.length - 2) == "-" ||
        this.hint.charAt(this.hint.length - 2) == "*" ||
        this.hint.charAt(this.hint.length - 2) == "/" ||
        this.hint.charAt(this.hint.length - 2) == "^"
      ) {
        return true;
      } else {
        return false;
      }
    },
    doAction(a) {
      //сначала ифаем случай с лишним действием
      if (!this.isThereAction || this.isLastAction()) {
        //чтобы не производить действия со строкой "ME"
        if (!(this.answer === "Math Error")) {
          if (this.afterEqual) {
            this.hint = this.answer + " " + a + " ";
            this.afterEqual = false;
          }
          if (this.answer) {
            this.num1 = this.commaToDot(this.answer);
            this.action = a;
            //ифаем замену уже стоявшего знака
            if (this.isLastAction()) {
              this.hint =
                this.hint.substring(0, this.hint.length - 2) + a + " ";
            } else {
              this.hint += " " + a + " ";
            }

            this.isNew = true;
            this.isThereAction = true;
          }
        }
      } else {
        this.errorMessages.push("You are allowed to use only one action");
      }
    },
    clear() {
      this.answer = "";
      this.errorMessages = [];
      this.action = "";
      this.hint = "";
      this.isThereAction = false;
    },

    removeDot(a){
      for(let i in a) {
        if (a[i] == ".") {
          
          a = a.substring(0, i)
          return a
        }
      }
      
    }
  },
  data: () => ({
    answer: "",
    action: "",
    num1: "",
    hint: "",
    isNew: false, //если мы набираем число после ответа
    isThereAction: false, //программа может выполнять только одно действие, данная переменная позволяет лишние действия отсечь
    afterEqual: false, //чтобы производить дальнейшие действия с полученным ответом
    errorMessages: [],
  }),
  //ниже находится код для чтения нажатий на клавиатуру
  mounted() {
    document.addEventListener("keypress", (e) => {
      let code = e.keyCode;
      if (code == "48") {
        this.numbers("0");
      } else if (code == "49") {
        this.numbers("1");
      } else if (code == "50") {
        this.numbers("2");
      } else if (code == "51") {
        this.numbers("3");
      } else if (code == "52") {
        this.numbers("4");
      } else if (code == "53") {
        this.numbers("5");
      } else if (code == "54") {
        this.numbers("6");
      } else if (code == "55") {
        this.numbers("7");
      } else if (code == "56") {
        this.numbers("8");
      } else if (code == "57") {
        this.numbers("9");
      } else if (code == "45") {
        this.doAction("-");
      } else if (code == "61") {
        this.doAction("+");
      } else if (code == "13") {
        this.doEqual();
      } else if (code == "47") {
        this.doAction("/");
      } else if (code == "42") {
        this.doAction("*");
      } else if (code == "127") {
        this.clear();
      }
    });
    document.addEventListener("keydown", (e) => {
      let key = e.key;
      if (key == "Backspace") {
        this.backspace();
      }
    });
  },
};
</script>


